SELECT DISTINCT "Customer_Tier__c" 
FROM "rtyjsc824_plan_write_critique_master_v2"."Account" 
WHERE "Customer_Tier__c" NOT IN ('Gold', 'Silver', 'Bronze', 'Platinum');

SELECT DISTINCT "Role__c" 
FROM "rtyjsc824_plan_write_critique_master_v2"."Contact" 
WHERE "Role__c" NOT IN ('Decision Maker', 'End User', 'Technical Contact', 'Executive Sponsor');

SELECT DISTINCT "Preferred_Language__c" 
FROM "rtyjsc824_plan_write_critique_master_v2"."Contact" 
WHERE "Preferred_Language__c" NOT IN ('DE', 'EN', 'FR', 'ES', 'IT');

SELECT DISTINCT "StageName" 
FROM "rtyjsc824_plan_write_critique_master_v2"."Opportunity" 
WHERE "StageName" NOT IN ('Prospecting', 'Qualification', 'Needs Analysis', 'Value Proposition', 'Id. Decision Makers', 'Perception Analysis', 'Proposal/Price Quote', 'Negotiation/Review', 'Closed Won', 'Closed Lost');

SELECT DISTINCT "Project_Status__c" 
FROM "rtyjsc824_plan_write_critique_master_v2"."Project__c" 
WHERE "Project_Status__c" NOT IN ('Active', 'Completed', 'In Planning', 'On Hold', 'Cancelled');

SELECT COUNT(*) AS null_lastname 
FROM "rtyjsc824_plan_write_critique_master_v2"."Contact" 
WHERE "LastName" IS NULL;

SELECT COUNT(*) AS null_name 
FROM "rtyjsc824_plan_write_critique_master_v2"."Account" 
WHERE "Name" IS NULL OR "Name" = '';

SELECT COUNT(*) AS negative_amounts 
FROM "rtyjsc824_plan_write_critique_master_v2"."Opportunity" 
WHERE "Amount" < 0;

SELECT 
  COUNT(*) FILTER (WHERE "AccountId" IS NULL) AS null_account_id
FROM "rtyjsc824_plan_write_critique_master_v2"."Opportunity";

SELECT 
  COUNT(*) FILTER (WHERE "AccountId" IS NULL) AS null_account_id
FROM "rtyjsc824_plan_write_critique_master_v2"."Contact";

SELECT 
  COUNT(*) FILTER (WHERE "Account__c" IS NULL) AS null_account_c
FROM "rtyjsc824_plan_write_critique_master_v2"."Installed_Asset__c";

SELECT 
  COUNT(*) FILTER (WHERE "Project__c" IS NULL) AS null_project_c
FROM "rtyjsc824_plan_write_critique_master_v2"."Installed_Asset__c";

SELECT 
  COUNT(*) FILTER (WHERE "kd_nummer" LIKE 'MISSING-%') AS missing_count
FROM "fixture_master_v2_src"."master_kontakte";
